events.body:
Is it possible that in commit 459fd3b0cc646f5ab02dd3cfd239c7a0418e6a32 (*Implement operator< for KeyOriginInfo and CExtPubKey *)

```cpp
else if (a.pubkey > b.pubkey) {
    return false;
}
```

is missing?

I've been (fixing and) playing with the `psbt` fuzz harness, and it uncovered a PSBT that has a different unique ID before and after roundtripping to serialization.

The PSBT in question is:
```
cHNidP8BAFwCAfsEAv8AAAAAcHdiFRUVFRUVFRUXcHNidCcBBQECAfsECgoBAAAAAAAAAAAAAAgAAAAAAGJ0JwoKAQwKV4gBBgABQElMAAoOCgAAANIAALcAAAAAAAIAAAAAAAH7BAAAAAAAAAA=
```

Here is a repro. This is a patch that applies on top of this PR:
```diff
diff --git a/src/test/psbt_tests.cpp b/src/test/psbt_tests.cpp
index 1e37b59121b..09c706e8c06 100644
--- a/src/test/psbt_tests.cpp
+++ b/src/test/psbt_tests.cpp
@@ -26,6 +26,20 @@ void CheckTimeLock(const std::string& base64_psbt, std::optional<uint32_t> timel
     }
 }
 
+void CheckRoundTrips(const std::string& base64_psbt)
+{
+    PartiallySignedTransaction psbt, psbt_roundtrip;
+    std::string error;
+    bool decoded = DecodeBase64PSBT(psbt, base64_psbt, error);
+    BOOST_CHECK_MESSAGE(decoded, error);
+
+    std::vector<uint8_t> roundtrip_bytes;
+    VectorWriter{roundtrip_bytes, 0, psbt};
+    SpanReader{roundtrip_bytes} >> psbt_roundtrip;
+    BOOST_CHECK_EQUAL(psbt.GetUniqueID(), psbt_roundtrip.GetUniqueID());
+    std::cout << psbt.GetUniqueID().ToString() << std::endl;
+}
+
 BOOST_AUTO_TEST_CASE(psbt2_timelock_test)
 {
     CheckTimeLock("cHNidP8BAgQCAAAAAQQBAQEFAQIB+wQCAAAAAAEOIAsK2SFBnByHGXNdctxzn56p4GONH+TB7vD5lECEgV/IAQ8EAAAAAAABAwgACK8vAAAAAAEEFgAUxDD2TEdW2jENvRoIVXLvKZkmJywAAQMIi73rCwAAAAABBBYAFE3Rk6yWSlasG54cyoRU/i9HT4UTAA==", 0);
@@ -38,6 +52,7 @@ BOOST_AUTO_TEST_CASE(psbt2_timelock_test)
     CheckTimeLock("cHNidP8BAgQCAAAAAQMEAAAAAAEEAQIBBQEBAfsEAgAAAAABDiAPdY2/vU2nwWyKMwnDyB4RAPVh6mRttbAXUsSF4b3enwEPBAEAAAABEQSLjcRiARIEECcAAAABDiA6Gzs8g31kiep6Mdjmx91QPAAb7z4GlY51dICNaMp4pQEPBAAAAAABEQSMjcRiAAEDCE+TNXcAAAAAAQQWABQLE1LKzQPPaqG388jWOIZxs0peEQA=", 1657048460);
     CheckTimeLock("cHNidP8BAgQCAAAAAQMEAAAAAAEEAQIBBQEBAfsEAgAAAAABDiAPdY2/vU2nwWyKMwnDyB4RAPVh6mRttbAXUsSF4b3enwEPBAEAAAAAAQ4gOhs7PIN9ZInqejHY5sfdUDwAG+8+BpWOdXSAjWjKeKUBDwQAAAAAAREEjI3EYgABAwhPkzV3AAAAAAEEFgAUCxNSys0Dz2qht/PI1jiGcbNKXhEA", 1657048460);
     CheckTimeLock("cHNidP8BAgQCAAAAAQMEAAAAAAEEAQIBBQEBAfsEAgAAAAABDiAPdY2/vU2nwWyKMwnDyB4RAPVh6mRttbAXUsSF4b3enwEPBAEAAAABEgQQJwAAAAEOIDobOzyDfWSJ6nox2ObH3VA8ABvvPgaVjnV0gI1oynilAQ8EAAAAAAERBIyNxGIAAQMIT5M1dwAAAAABBBYAFAsTUsrNA89qobfzyNY4hnGzSl4RAA==", std::nullopt);
+    CheckRoundTrips("cHNidP8BAFwCAfsEAv8AAAAAcHdiFRUVFRUVFRUXcHNidCcBBQECAfsECgoBAAAAAAAAAAAAAAgAAAAAAGJ0JwoKAQwKV4gBBgABQElMAAoOCgAAANIAALcAAAAAAAIAAAAAAAH7BAAAAAAAAAA=");
 }
 
 BOOST_AUTO_TEST_SUITE_END()
```

---

This was a bug in the implementation of `GetUniqueID()`, see https://github.com/bitcoin/bitcoin/pull/21283#discussion_r2879797382.

Leaving a review to surface some comments on the first ~15 commits. I think the most important things are:
- I don't think the logic in merging the modifiable bitsets is correct;
- I don't think we should UB / crash in various methods if a PSBT input/output is missing some fields. (I understand those are always set when the input/output comes from a top-level PSBT, but still.)

Here is also a fix / improvement for the `psbt` fuzz target. I've been running this (along with #34725) for a few days now with no crash:
```diff
diff --git a/src/test/fuzz/psbt.cpp b/src/test/fuzz/psbt.cpp
index 4ea75eb4d61..c10716f9c11 100644
--- a/src/test/fuzz/psbt.cpp
+++ b/src/test/fuzz/psbt.cpp
@@ -33,6 +33,29 @@ FUZZ_TARGET(psbt)
     }
     const PartiallySignedTransaction psbt = psbt_mut;
 
+    // We are on purpose not forward compatible, and version 1 is disabled.
+    const auto psbt_version{psbt.GetVersion()};
+    Assert(psbt_version == 0 || psbt_version == 2);
+
+    // The transaction version is always set regardless of the PSBT version.
+    Assert(psbt.tx_version.has_value());
+
+    // PSBT v0 must always have a transaction. PSBT v2 must never have one.
+    if (psbt_version == 0) {
+        Assert(psbt.tx.has_value());
+        // When present the transaction must be consistent with the PSBT metadata.
+        Assert(psbt.tx->vin.size() == psbt.inputs.size());
+        Assert(psbt.tx->vout.size() == psbt.outputs.size());
+        // And it is always possible to create a PSBT from the inner transaction.
+        (void)PartiallySignedTransaction{*psbt.tx, /*version=*/0};
+        (void)PartiallySignedTransaction{*psbt.tx, /*version=*/2};
+    } else {
+        Assert(!psbt.tx.has_value());
+        Assert(psbt.m_version.has_value());
+        // FIXME: this crashes but the specs mandate that tx version be >=2
+        // Assert(*psbt.tx_version >= 2);
+    }
+
     // A PSBT must roundtrip.
     PartiallySignedTransaction psbt_roundtrip;
     std::vector<uint8_t> psbt_ser;
@@ -52,28 +75,36 @@ FUZZ_TARGET(psbt)
 
     (void)psbt.IsNull();
 
-    std::optional<CMutableTransaction> tx = psbt.tx;
-    if (tx) {
-        const CMutableTransaction& mtx = *tx;
-        const PartiallySignedTransaction psbt_from_tx{mtx};
-    }
-
     for (const PSBTInput& input : psbt.inputs) {
         (void)PSBTInputSigned(input);
         (void)input.IsNull();
+        CTxOut tx_out;
+        if (input.GetUTXO(tx_out)) {
+            (void)tx_out.IsNull();
+            (void)tx_out.ToString();
+        }
+        // A PSBT input must roundtrip to signature data.
+        PSBTInput input_fill{psbt_version};
+        SignatureData sig_data;
+        input.FillSignatureData(sig_data);
+        input_fill.FromSignatureData(sig_data);
+        // FIXME: actually it crashes. Do we want this invariant?
+        // Assert(input == input_fill);
     }
     (void)CountPSBTUnsignedInputs(psbt);
 
     for (const PSBTOutput& output : psbt.outputs) {
         (void)output.IsNull();
-    }
-
-    for (size_t i = 0; i < psbt.tx->vin.size(); ++i) {
-        CTxOut tx_out;
-        if (psbt.inputs.at(i).GetUTXO(tx_out)) {
-            (void)tx_out.IsNull();
-            (void)tx_out.ToString();
-        }
+        // PSBT v2 outputs must have amount and script set. PSBT v0 outputs must not have them
+        // set in the serialization, but we cache them from the inner tx after parsing.
+        Assert(output.amount.has_value() && output.script.has_value());
+        // A PSBT output must roundtrip to signature data.
+        PSBTOutput output_fill{psbt_version};
+        SignatureData sig_data;
+        output.FillSignatureData(sig_data);
+        output_fill.FromSignatureData(sig_data);
+        // FIXME: actually it crashes. Do we want this invariant?
+        //Assert(output == output_fill);
     }
 
     psbt_mut = psbt;
@@ -99,7 +130,9 @@ FUZZ_TARGET(psbt)
         (void)psbt_mut.AddInput(psbt_in);
     }
     for (const auto& psbt_out : psbt_merge.outputs) {
-        Assert(psbt_mut.AddOutput(psbt_out));
+        (void)psbt_mut.AddOutput(psbt_out);
     }
     psbt_mut.unknown.insert(psbt_merge.unknown.begin(), psbt_merge.unknown.end());
+
+    RemoveUnnecessaryTransactions(psbt_mut);
 }
```

This change makes combinepsbt preserve proprietary fields instead of dropping them during PSBT merge, similar to the https://github.com/bitcoin/bitcoin/pull/34893

```diff
--- a/src/psbt.cpp
+++ b/src/psbt.cpp
@@ -75,6 +75,7 @@ bool PartiallySignedTransaction::Merge(const PartiallySignedTransaction& psbt)
         m_tx_modifiable = this_modifiable;
     }

+    m_proprietary.insert(psbt.m_proprietary.begin(), psbt.m_proprietary.end());
     unknown.insert(psbt.unknown.begin(), psbt.unknown.end());

     return true;
@@ -435,6 +436,7 @@ bool PSBTInput::Merge(const PSBTInput& input)
     hash160_preimages.insert(input.hash160_preimages.begin(), input.hash160_preimages.end());
     hash256_preimages.insert(input.hash256_preimages.begin(), input.hash256_preimages.end());
     hd_keypaths.insert(input.hd_keypaths.begin(), input.hd_keypaths.end());
+    m_proprietary.insert(input.m_proprietary.begin(), input.m_proprietary.end());
     unknown.insert(input.unknown.begin(), input.unknown.end());
     m_tap_script_sigs.insert(input.m_tap_script_sigs.begin(), input.m_tap_script_sigs.end());
     m_tap_scripts.insert(input.m_tap_scripts.begin(), input.m_tap_scripts.end());
@@ -523,6 +525,7 @@ bool PSBTOutput::IsNull() const
 bool PSBTOutput::Merge(const PSBTOutput& output)
 {
     hd_keypaths.insert(output.hd_keypaths.begin(), output.hd_keypaths.end());
+    m_proprietary.insert(output.m_proprietary.begin(), output.m_proprietary.end());
     unknown.insert(output.unknown.begin(), output.unknown.end());
     m_tap_bip32_paths.insert(output.m_tap_bip32_paths.begin(), output.m_tap_bip32_paths.end());
