The following test case might be useful to address it:

```cpp
BOOST_AUTO_TEST_CASE(psbt2_add_input_no_locktime_with_timelocked_existing)
{
    // When an existing input has only time_locktime set (no height_locktime),
    // adding a new input with no required timelocks must succeed. The
    // iterate_inputs flag should be false (new input has no timelocks), so the
    // locktime-compatibility loop is skipped. If the loop ran unconditionally,
    // the check `if (time_lock == std::nullopt)` would incorrectly trigger and
    // reject the new input.
    PartiallySignedTransaction psbt;
    psbt.m_version = 2;
    psbt.tx_version = 2;
    psbt.m_tx_modifiable = std::bitset<8>(0x01); // bit 0: inputs modifiable

    // Existing input with only time_locktime set (no height_locktime)
    PSBTInput existing_input(2);
    existing_input.prev_txid = Txid::FromHex("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa").value();
    existing_input.prev_out = 0;
    existing_input.time_locktime = 1000000;
    psbt.inputs.push_back(existing_input);

    // New input with no timelocks at all — must be accepted
    PSBTInput new_input(2);
    new_input.prev_txid = Txid::FromHex("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb").value();
    new_input.prev_out = 0;
    BOOST_CHECK(psbt.AddInput(new_input));
    BOOST_CHECK_EQUAL(psbt.inputs.size(), 2U);
}
